theme.custom_css_code:
.cr32-brand-table-wrap {
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.cr32-brand-table-scroll {
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  border: 1px solid #d6d6d6;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.88);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);
}

.cr32-brand-table {
  width: 100%;
  min-width: 620px;
  border-collapse: collapse;
  color: #1f1f1f;
}

.cr32-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid #e6e6e6;
  vertical-align: top;
  font-size: 15px;
  line-height: 1.45;
}

.cr32-brand-table tr:last-child td {
  border-bottom: none;
}

.cr32-brand-table td:first-child {
  width: 34%;
  font-weight: 700;
  color: #111111;
  background: rgba(0, 0, 0, 0.02);
}

@media (max-width: 640px) {
  .cr32-brand-table td {
    padding: 12px 14px;
    font-size: 14px;
  }
}
.cr32-games-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.cr32-game-card {
  position: relative;
  overflow: hidden;
  border-radius: 20px;
  padding: 20px 18px;
  min-height: 150px;
  background: linear-gradient(180deg, rgba(255,255,255,0.94) 0%, rgba(247,247,247,0.9) 100%);
  border: 1px solid #d7d7d7;
  box-shadow: 0 10px 24px rgba(0, 0, 0, 0.06);
}

.cr32-game-card::after {
  content: "";
  position: absolute;
  right: -22px;
  bottom: -22px;
  width: 88px;
  height: 88px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(194, 0, 23, 0.14) 0%, rgba(194, 0, 23, 0) 72%);
}

.cr32-game-icon {
  font-size: 30px;
  line-height: 1;
  margin-bottom: 16px;
}

.cr32-game-name {
  font-size: 19px;
  line-height: 1.2;
  font-weight: 700;
  color: #121212;
  margin-bottom: 10px;
}

.cr32-game-meta {
  font-size: 14px;
  line-height: 1.5;
  color: #555555;
  max-width: 220px;
}

@media (max-width: 900px) {
  .cr32-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 560px) {
  .cr32-games-grid {
    grid-template-columns: 1fr;
  }

  .cr32-game-card {
    min-height: auto;
  }
}
.cr32-chart-box {
  width: 100%;
  padding: 22px;
  border-radius: 22px;
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid #d8d8d8;
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.06);
  font-family: Arial, sans-serif;
}

.cr32-chart-row + .cr32-chart-row {
  margin-top: 16px;
}

.cr32-chart-label {
  margin-bottom: 8px;
  font-size: 14px;
  font-weight: 700;
  color: #1c1c1c;
}

.cr32-chart-track {
  width: 100%;
  height: 18px;
  border-radius: 999px;
  background: #e4e4e4;
  overflow: hidden;
}

.cr32-chart-fill {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  height: 100%;
  min-width: 52px;
  padding-right: 8px;
  border-radius: 999px;
  background: linear-gradient(90deg, #9c0f1c 0%, #d51c30 100%);
}

.cr32-chart-fill span {
  font-size: 11px;
  line-height: 1;
  font-weight: 700;
  color: #ffffff;
}

.cr32-w-95 { width: 95%; }
.cr32-w-90 { width: 90%; }
.cr32-w-89 { width: 89%; }
.cr32-w-88 { width: 88%; }
.cr32-w-84 { width: 84%; }
.cr32-w-72 { width: 72%; }

@media (max-width: 640px) {
  .cr32-chart-box {
    padding: 16px;
    border-radius: 18px;
  }

  .cr32-chart-label {
    font-size: 13px;
  }

  .cr32-chart-track {
    height: 16px;
  }
}
